10→export function normalizeSandboxInitialFilePath(relativePath: string) {
11→  const normalized = relativePath.replace(/\\/g, '/').replace(/^\/+/, '');
12→  if (!normalized || normalized === '.' || normalized === '..' || normalized.startsWith('../')) {
13→    throw new Error('Invalid initial file path');
14→  }
15→  return `/${normalized}`;
