17→// This normalizes every file discovered under the host `skills` directory
18→// into a sandbox path shaped like `/skills/xxx`.
19→export function resolveSandboxSkillFilePath(relativePath: string) {
20→  return normalizeSandboxInitialFilePath(`${SANDBOX_SKILLS_ROOT}/${relativePath}`);
21→}
