28→class NodeVfsConversationSandboxSession implements ConversationSandboxSession {
29→  private readonly decoder = new TextDecoder();
30→
31→  constructor(readonly backend: VfsSandbox) {}
32→
33→  get workingDirectory() {
34→    return this.backend.workingDirectory;
35→  }
36→
37→  static async create(initialFiles?: SandboxInitialFiles) {
38→    const backend = await VfsSandbox.create({ initialFiles });
39→    return new NodeVfsConversationSandboxSession(backend);
40→  }
41→
42→  async listFiles() {
43→    const entries = await this.backend.globInfo('**/*', '/');
44→    return entries
45→      .filter(entry => !entry.is_dir)
46→      .map(entry => normalizeListedSandboxPath(entry.path))
47→      .sort((a, b) => a.localeCompare(b));
48→  }
49→
50→  async readFile(relativePath: string) {
51→    const normalizedPath = normalizeSandboxFilePath(relativePath);
52→    const [result] = await this.backend.downloadFiles([normalizedPath]);
53→    if (!result || result.error || !result.content) {
54→      throw new Error(`Session file not found: ${normalizedPath}`);
55→    }
56→    return this.decoder.decode(result.content);
57→  }
58→
59→  async stop() {
60→    await this.backend.stop();
61→  }
62→}
