 22→export class CompositeSandboxInitialFilesProvider implements SandboxInitialFilesProvider {
 23→  constructor(private readonly providers: SandboxInitialFilesProvider[]) { }
 24→
 25→  async getInitialFiles() {
 26→    const initialFiles: SandboxInitialFiles = {};
 27→
 28→    for (const provider of this.providers) {
 29→      Object.assign(initialFiles, await provider.getInitialFiles());
 30→    }
 31→
 32→    return initialFiles;
 33→  }
