 82→function extractNamespace(metadata?: StreamMetadata): string[] {
 83→  if (!metadata) {
 84→    return [];
 85→  }
 86→
 87→  const rawCandidates: unknown[] = [
 88→    metadata.namespace,
 89→    metadata.langgraph_path,
 90→    metadata.checkpoint_ns,
 91→  ];
 92→
 93→  const flattened = rawCandidates.flatMap(candidate => {
 94→    if (Array.isArray(candidate)) {
 95→      return candidate;
 96→    }
 97→    if (typeof candidate === 'string') {
 98→      return candidate.split(/[|,]/g);
 99→    }
100→    return [];

100→    return [];
101→  });
102→
103→  const namespace = flattened
104→    .flatMap(value => (typeof value === 'string' ? expandNamespaceToken(value) : []))
105→    .map(segment => segment.trim())
106→    .filter(segment => segment && segment !== 'root');
107→
108→  return Array.from(new Set(namespace));
109→}
