424→export function dispatchStreamEvent(
425→  event: string,
426→  ctx: StreamContext,
427→  state: ToolInputState,
428→): IGraphEvent | undefined {
429→  const { run_id, name, data, node, metadata } = ctx;
430→  const subagent = buildSubagentInfo(name, data, metadata, state);
431→
432→  // 默认关闭流式调试，避免敏感数据落盘与同步 IO 阻塞。
433→  writeStreamDebugLog(event, name, node, data);
434→
435→  switch (event) {
436→    case 'on_chain_start':
437→      return handleChainStart(name, node, subagent);
438→    case 'on_chain_end':
439→      return handleChainEnd(name, node, subagent);
440→    case 'on_chat_model_start':
441→      return handleChatModelStart(node, subagent);
442→    case 'on_chat_model_end':
443→      return handleChatModelEnd(node, data, subagent);
444→    case 'on_chat_model_stream':
445→      return handleChatModelStream(data as { chunk: unknown }, node, state, subagent);
446→    case 'on_chain_stream':
447→      return handleChainStream(data as { chunk?: Record<string, unknown> }, node, subagent);
448→    case 'on_tool_start':
449→      return handleToolStart(
450→        run_id,
451→        name,
452→        data as { input: { input: string } },
453→        node,
454→        state,
455→        subagent,
456→      );
457→    case 'on_tool_end':
458→      return handleToolEnd(
459→        run_id,
460→        name,
461→        data as { output: { artifact: unknown; content: unknown } },
462→        node,
463→        subagent,
464→      );
465→    case 'on_tool_error':
466→      return handleToolError(
467→        run_id,
468→        name,
469→        data as { error?: unknown },
470→        node,
471→        subagent,
472→      );
473→    default:
474→      return undefined;
475→  }
476→}
